git -C /tmp/selfservice-repo pull origin main && python3 -c "import os, yaml, json
kb_path = '/tmp/selfservice-repo/data/knowledge'
result = {'operation': [], 'noc': [], 'customer': []}
for root, _, files in os.walk(kb_path):
    for f in files:
        if f.endswith('.yaml'):
            filepath = os.path.join(root, f)
            with open(filepath, 'r', encoding='utf-8') as stream:
                try:
                    data = yaml.safe_load(stream) or {}
                    file_default = data.get('default_audience', ['operation'])
                    if not isinstance(file_default, list): file_default = ['operation']
                    cats = data.get('categories', {})
                    for cat_id, cat_val in cats.items():
                        sections = cat_val.get('sections', {})
                        for sec_id, sec_val in sections.items():
                            for entry in sec_val.get('entries', []):
                                audience = entry.get('audience', file_default)
                                if not isinstance(audience, list): audience = ['operation']
                                item = {'id': entry.get('id'), 'intent': entry.get('intent'), 'answer': entry.get('answer'), 'keywords': entry.get('keywords', []), 'refs': entry.get('refs', [])}
                                for r in ['operation', 'noc', 'customer']:
                                    if r in audience: result[r].append(item)
                except Exception: pass
print(json.dumps(result))"

